      "title": "Sinagogue",
      "summary": "Build a sin-agogue underneath the church to turn the religious tensions that divide the world into a fun burn experience to unite our community of sinners",
      "status": "IDEA",
      "noOfFunders": 0,
      "noOfComments": 3,
      "percentageFunded": 0,
      "minGoal": 1600,
      "maxGoal": 6000,
