      "id": "cmnh934t1000q145fkf0w8r7p",
      "title": "Bohemian Queen's Chalet",
      "summary": "Step inside the Bohemian Queen's Chalet — a black tent where ancient Bohemian witchcraft meets the daimonic intelligence of machines. ",
      "status": "IDEA",
      "noOfFunders": 0,
      "noOfComments": 0,
      "percentageFunded": 360,
      "minGoal": 5000,
      "maxGoal": 5000,
      "income": 18000,
