      "title": "Inconvenient Popsicles",
      "summary": "Handmade popsicles with unexpected flavors and a salty edge. Shaped like something that no longer exists. You’ll make it melt. Deal with it.",
      "status": "IDEA",
      "noOfFunders": 0,
      "noOfComments": 0,
      "percentageFunded": 206.18,
      "minGoal": 2750,
      "maxGoal": 4800,
