      "id": "cmnw09gaq0002ozd12fexs9qa",
      "title": "The world through my eyes - visual impairment simulator",
      "summary": "Come with me and have a new sensory experience what it’s like living with a visual impairment. A chance to enhance your other senses in a playful way. ",
      "status": "IDEA",
      "noOfFunders": 0,
      "noOfComments": 0,
      "percentageFunded": 0,
      "minGoal": 700,
      "maxGoal": 700,
