      "id": "cmn3jnblo0004kyk6stxh8n3x",
      "title": "Kishmastle Spacestation",
      "summary": "A spaced out sound camp",
      "status": "IDEA",
      "noOfFunders": 0,
      "noOfComments": 0,
      "percentageFunded": 1046.48,
      "minGoal": 32700,
      "maxGoal": 81850,
